```javascript
// TiLT's Solution: Expand Around Centers O(n²)
function longestPalindrome(s) {
  let longest = "";

  for (let i = 0; i < s.length; i++) {
    // Check odd-length palindromes (center = i)
    let odd = expandAroundCenter(s, i, i);
    // Check even-length palindromes (center = i, i+1)
    let even = expandAroundCenter(s, i, i + 1);

    let current = odd.length > even.length ? odd : even;
    if (current.length > longest.length) longest = current;
  }
  return longest;
}

function expandAroundCenter(s, left, right) {
  while (left >= 0 && right < s.length && s[left] === s[right]) {
    left--; right++;
  }
  return s.substring(left + 1, right);
}
```

